{
var src = inputs.Length > 0 ? inputs[0] : null;
if (src == null)
    return new PixelBuffer(context.TileSize, context.TileSize);

var mode = GetChoice(parameters, "mode", "horizontalScanlines");
var density = GetFloat(parameters, "density", 0.5f);
var intensity = GetFloat(parameters, "intensity", 0.4f);
var brightness = GetFloat(parameters, "brightness", 0.1f);
var curvature = GetFloat(parameters, "curvature", 0f);
var preserveAlpha = GetBool(parameters, "preserveAlpha", true);

var size = context.TileSize;
var result = new PixelBuffer(size, size);
var lineSpacing = Math.Max(2, (int)((1f - density * 0.7f) * 8f + 2f));
var cx = size * 0.5f;
var cy = size * 0.5f;

result.ParallelForEachPixel((x, y) =>
{
    var (r, g, b, a) = src.GetPixel(x, y);

    // Screen curvature: displace coordinates
    float scanX = x, scanY = y;
    if (curvature > 0.001f)
    {
        var nx = (x - cx) / cx;
        var ny = (y - cy) / cy;
        var dist2 = nx * nx + ny * ny;
        scanX = x + nx * dist2 * curvature * cx;
        scanY = y + ny * dist2 * curvature * cy;

        // Sample from curved position
        var sx = (int)Math.Clamp(scanX, 0, size - 1);
        var sy = (int)Math.Clamp(scanY, 0, size - 1);
        (r, g, b, a) = src.GetPixel(sx, sy);
    }

    // Compute scanline mask
    var lineVal = 1f;
    switch (mode)
    {
        case "horizontalScanlines":
        {
            var linePos = (int)scanY % lineSpacing;
            lineVal = linePos == 0 ? (1f - intensity) : 1f;
            break;
        }
        case "verticalScanlines":
        {
            var linePos = (int)scanX % lineSpacing;
            lineVal = linePos == 0 ? (1f - intensity) : 1f;
            break;
        }
        case "grid":
        {
            var hPos = (int)scanY % lineSpacing;
            var vPos = (int)scanX % lineSpacing;
            lineVal = (hPos == 0 || vPos == 0) ? (1f - intensity) : 1f;
            break;
        }
        case "shadowMask":
        {
            var shadowX = (int)(scanX * 0.5f) % 4;
            lineVal = shadowX < 2 ? (1f - intensity * 0.7f) : 1f;
            var shadowY = (int)(scanY * 0.5f) % 4;
            if (shadowY < 2) lineVal *= (1f - intensity * 0.3f);
            break;
        }
    }

    // Brightness boost (CRT phosphor glow)
    var boost = brightness;
    r = Math.Clamp(r * lineVal + boost, 0f, 1f);
    g = Math.Clamp(g * lineVal + boost * 0.9f, 0f, 1f);
    b = Math.Clamp(b * lineVal + boost * 0.8f, 0f, 1f);

    // RGB bloom on bright areas
    if (r + g + b > 2f)
    {
        var bloom = (r + g + b - 2f) * 0.2f;
        r = Math.Clamp(r + bloom, 0f, 1f);
        g = Math.Clamp(g + bloom * 0.8f, 0f, 1f);
        b = Math.Clamp(b + bloom * 0.6f, 0f, 1f);
    }

    result.SetPixel(x, y, r, g, b, preserveAlpha ? a : 1f);
});

return result;
}
